VALUES
  ('elementary-0a2fc18c-moex-00533', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '有關刑事被告自白證明力之敘述，下列何者正確？', '["被告之自白，得作為被告有罪判決之唯一證據", "被告自白之證據能力與證明力為相同的概念", "告訴人經改列證人到庭具結之證言，得作為被告自白之補強證據", "被告自白之補強證據，以能證明被告全部犯罪事實為必要"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00534', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列關於證據之敘述，何者正確？', '["有證據能力之證據，即可作為判斷被告是否有罪之依據", "經過合法調查之證據，即可作為判斷被告是否有罪之依據", "那些證據可以判斷被告是否有罪，全憑法院決定", "有證據能力且經合法調查之證據，即可作為判斷被告是否有罪之依據"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00535', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '檢察官起訴被告涉犯傷害罪嫌，但法院進行審判程序時，認被告之傷害行為應構成重傷害未遂罪， 且依照起訴書記載之犯罪事實，被告另涉及妨害自由行為。依實務見解，此時法院應如何處理？', '["法院僅依起訴罪名審理並終結案件為已足", "基於不告不理原則，妨害自由部分未起訴，法院毋庸審理", "法院應告知被告原先起訴之傷害罪名可能變更為重傷害未遂罪名，且應一併審理妨害自由部分， 同時告知被告尚涉及妨害自由之犯罪嫌疑及罪名", "法院應曉諭檢察官追加起訴妨害自由部分，始得加以審理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00536', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列關於刑法第23條正當防衛之敘述，何者錯誤？', '["須對於現在不法之侵害為之", "須為出於防衛自己或他人權利之行為", "防衛行為如過當，則僅得減輕或免除其刑", "僅得對於侵害自己或他人生命、身體、自由、財產等權利之行為而為防衛行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00537', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列關於刑法上公務員之敘述，何者錯誤？', '["任職於公立醫院之醫師，就其日常提供之醫療服務並非公權力之行使，並非身分公務員", "若醫師依法令從事於公共事務，而具法定職務權限時，仍應認其屬於授權公務員", "替代役役男服役期間，比照現役軍人身分，絕對是公務員", "替代役之警察役別，奉派往監獄擔任崗哨、巡邏勤務者，應視為刑法上之公務員"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00538', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '某甲參加公務人員考試時，以電子舞弊方式因而通過考試，甲有無犯罪？', '["構成刑法第339條之詐欺罪", "構成刑法第137條之以詐術使考試發生不正確結果罪", "偽造文書罪", "不犯罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00539', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列關於刑法第15條第1項規定不作為犯之敘述，何者錯誤？', '["以法律上有防止之義務者為限", "須消極不作為與積極作為等價", "須能防止而不防止", "不作為犯按作為犯之刑減輕之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00540', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列關於刑事訴訟法之辯護依賴權，何者錯誤？', '["被告得隨時選任辯護人", "犯罪嫌疑人受司法警察官或司法警察調查者，得隨時選任辯護人", "只有被告或犯罪嫌疑人自己才能選任辯護人，其他人一概不行", "被告或犯罪嫌疑人之配偶得獨立為被告或犯罪嫌疑人選任辯護人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00541', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '刑法關於過失之敘述，何者錯誤？', '["刑法處罰過失行為，以條文中有特別規定者為限", "對於構成犯罪事實，預見其能發生而確信其不發生者，非過失", "犯罪行為非出於故意或過失者，刑法不處罰", "按照情節應注意，並能注意，而不注意者，為過失"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00542', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '甲犯下列何者之罪，縱於犯罪後自白且自動繳交全部所得財物，仍不得減輕或免除其刑？', '["甲犯貪污治罪條例第4條之罪", "甲犯貪污治罪條例第5條之罪", "甲犯貪污治罪條例第6條之罪", "甲犯貪污治罪條例第13條之罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:16+00:00", "source_pdf_sha1": "9565b8c6d34e", "answer_pdf_sha1": "411503a886ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL)
